INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer's application fails to bind to port 8080 and returns 'Address already in use'. The developer needs to identify which process is currently occupying port 8080. Which command will BEST provide the process name and PID using that port?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"netstat -tulpn | grep :8080"},{"id":"b","text":"ping localhost -p 8080"},{"id":"c","text":"traceroute localhost 8080"},{"id":"d","text":"ip link show | grep 8080"}]$patch$::jsonb, $patch$["a"]$patch$::jsonb, $patch$'netstat -tulpn | grep :8080' lists all TCP (-t) and UDP (-u) listening (-l) sockets, displaying the process name and PID (-p) without resolving hostnames (-n) for speed. Filtering with grep for ':8080' quickly identifies which process is bound to that port. On modern systems, 'ss -tulpn | grep :8080' is the preferred alternative using the iproute2 'ss' utility. 'ping' is an ICMP utility used for host reachability testing and has no ability to specify ports. 'traceroute' traces routing paths to a host and cannot query which process is bound to a port. 'ip link show' displays network interface information and has no relation to port bindings.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man8/netstat.8.html","label":"man page: netstat"},{"url":"https://man7.org/linux/man-pages/man8/ss.8.html","label":"man page: ss"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer's application fails to bind to port 8080 and returns 'Address already in use'. The developer needs to identify which process is currently occupying port 8080. Which command will BEST provide the process name and PID using that port?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$While troubleshooting a network connectivity issue, an administrator runs 'ip route show' and finds no default gateway entry in the routing table. Which command would CORRECTLY add a default gateway of 192.168.1.1 for immediate (non-persistent) use?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"ip route add default via 192.168.1.1"},{"id":"b","text":"route add default gw 192.168.1.1 eth0"},{"id":"c","text":"ifconfig eth0 gateway 192.168.1.1"},{"id":"d","text":"nmcli con mod eth0 ipv4.gateway 192.168.1.1"}]$patch$::jsonb, $patch$["a"]$patch$::jsonb, $patch$'ip route add default via 192.168.1.1' is the modern, correct syntax using the 'ip' utility from the iproute2 package to add a default route immediately. This change takes effect instantly but is not persistent across reboots. The legacy 'route' command (option B) is deprecated on modern distributions and uses different syntax ('route add default gw'). 'ifconfig' does not support gateway configuration — it only manages interface-level settings. 'nmcli con mod' modifies a NetworkManager connection profile persistently, which is the correct tool for persistent changes but requires a subsequent 'nmcli con up' to apply immediately, and is less direct for an emergency one-time fix.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man8/ip-route.8.html","label":"man page: ip-route"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/configuring-static-routes_configuring-and-managing-networking","label":"Red Hat - Configuring static routes"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$While troubleshooting a network connectivity issue, an administrator runs 'ip route show' and finds no default gateway entry in the routing table. Which command would CORRECTLY add a default gateway of 192.168.1.1 for immediate (non-persistent) use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A system administrator observes that a Linux server is experiencing very high load averages (15.0, 14.8, 14.5 on a 4-core system) even though CPU utilization appears normal. What is the MOST likely explanation for this discrepancy?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The system clock is out of sync, causing incorrect load calculation"},{"id":"b","text":"There are many processes blocked in an uninterruptible sleep state waiting on I/O"},{"id":"c","text":"The kernel has been compiled without SMP support"},{"id":"d","text":"Swap usage is near zero, starving the CPU scheduler"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Linux load average counts not only processes actively using CPU but also processes in uninterruptible sleep state (D state), which typically means they are waiting on I/O (disk, network, NFS, etc.). A high load average with normal CPU utilization is a classic indicator of I/O wait bottlenecks. This can be confirmed with 'iostat', 'iotop', or by looking at the 'wa' (I/O wait) column in 'top'. An out-of-sync clock does not affect load average calculations. SMP support absence would show as single-core scheduling but would also impact CPU metrics. Low swap usage does not cause high load averages.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/uptime.1.html","label":"man page: uptime"},{"url":"https://www.brendangregg.com/blog/2017-08-08/linux-load-averages.html","label":"Linux Load Averages - Brendan Gregg"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A system administrator observes that a Linux server is experiencing very high load averages (15.0, 14.8, 14.5 on a 4-core system) even though CPU utilization appears normal. What is the MOST likely explanation for this discrepancy?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A production server's /var/log partition has become 100% full, causing several services to stop logging and behave erratically. The administrator needs to free space immediately without rebooting. Which action is the SAFEST immediate step?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Run 'rm -rf /var/log/*' to clear all logs immediately"},{"id":"b","text":"Use 'truncate -s 0' on large, non-critical rotated log files such as /var/log/syslog.1"},{"id":"c","text":"Unmount /var/log and delete the partition to reclaim space"},{"id":"d","text":"Kill all running services to stop log generation"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Using 'truncate -s 0' on old rotated log files (e.g., .1, .2, .gz files) safely frees space without deleting active log files that running processes may have open. Deleting a file that a process has open with 'rm' does not free the inode and disk blocks until the process closes the file handle, whereas truncating it to zero bytes immediately reclaims the space. 'rm -rf /var/log/*' is dangerous as it may remove active log files open by running processes and delete critical audit or security logs. Unmounting /var/log on a live system would break all logging services. Killing services avoids the problem but does not resolve it and causes service disruption.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/truncate.1.html","label":"man page: truncate"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/index","label":"Red Hat - Log file management with logrotate"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A production server's /var/log partition has become 100% full, causing several services to stop logging and behave erratically. The administrator needs to free space immediately without rebooting. Which action is the SAFEST immediate step?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is troubleshooting intermittent SSH connectivity issues to a remote server. The connection sometimes hangs during negotiation. Which command provides the MOST verbose output to help diagnose the SSH handshake process?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"ssh -v user@remotehost"},{"id":"b","text":"ssh -vvv user@remotehost"},{"id":"c","text":"ssh -o StrictHostKeyChecking=no user@remotehost"},{"id":"d","text":"netstat -an | grep :22"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'ssh -vvv' enables the maximum verbosity level (level 3) for the SSH client, providing detailed debug output for each stage of the SSH handshake including key exchange, authentication methods attempted, and channel setup. This level of output is most useful for diagnosing complex or intermittent negotiation issues. 'ssh -v' enables only level 1 verbosity, which is less detailed. '-o StrictHostKeyChecking=no' disables host key verification but adds no diagnostic information. 'netstat -an | grep :22' shows TCP connection states on port 22 but provides no application-layer debug detail.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/ssh.1.html","label":"man page: ssh"},{"url":"https://www.openssh.com/manual.html","label":"OpenSSH Manual Pages"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is troubleshooting intermittent SSH connectivity issues to a remote server. The connection sometimes hangs during negotiation. Which command provides the MOST verbose output to help diagnose the SSH handshake process?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A junior administrator reports that a bash script they wrote exits with code 127 when executed. What does exit code 127 specifically indicate?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The script was terminated by a SIGKILL signal"},{"id":"b","text":"The script exited normally with no errors"},{"id":"c","text":"A command referenced in the script was not found"},{"id":"d","text":"The script encountered a syntax error and could not be parsed"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$Exit code 127 is a standard bash shell exit code meaning 'command not found.' This occurs when the shell cannot locate an executable or script referenced by name, typically because it is not in the PATH or does not exist. A SIGKILL termination would result in exit code 137 (128 + signal number 9). A normal successful exit returns code 0. A syntax error typically causes the script to exit with code 1 or 2 and is accompanied by a syntax error message, not code 127.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.gnu.org/software/bash/manual/bash.html#Exit-Status","label":"GNU Bash Manual - Exit Status"},{"url":"https://tldp.org/LDP/abs/html/exitcodes.html","label":"Advanced Bash-Scripting Guide - Exit Codes With Special Meanings"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A junior administrator reports that a bash script they wrote exits with code 127 when executed. What does exit code 127 specifically indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$After a kernel update, a Linux system boots into an emergency shell with the error: 'Failed to mount /data: can't read superblock'. Which command is MOST appropriate to attempt repair of the ext4 filesystem on the /data partition before mounting it?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"mount -o remount,rw /data"},{"id":"b","text":"fsck -y /dev/sdb1"},{"id":"c","text":"tune2fs -l /dev/sdb1"},{"id":"d","text":"badblocks -v /dev/sdb1"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'fsck -y /dev/sdb1' runs a filesystem consistency check and automatically answers 'yes' to repair prompts, making it the correct tool to repair a corrupted ext4 filesystem. fsck must be run on an unmounted filesystem, which is satisfied during the emergency boot state. 'mount -o remount,rw' attempts to remount the filesystem and will fail if the superblock is unreadable. 'tune2fs -l' only reads and displays filesystem parameters; it does not perform repairs. 'badblocks' scans for bad disk sectors but does not repair filesystem metadata like the superblock.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man8/fsck.8.html","label":"man page: fsck"},{"url":"https://man7.org/linux/man-pages/man8/e2fsck.8.html","label":"man page: e2fsck"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$After a kernel update, a Linux system boots into an emergency shell with the error: 'Failed to mount /data: can't read superblock'. Which command is MOST appropriate to attempt repair of the ext4 filesystem on the /data partition before mounting it?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux server cannot reach any external hosts by hostname, but IP address connectivity works fine. DNS resolution was working yesterday. Which file should the administrator inspect FIRST to verify the system's configured DNS resolver addresses?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"/etc/hosts"},{"id":"b","text":"/etc/nsswitch.conf"},{"id":"c","text":"/etc/resolv.conf"},{"id":"d","text":"/etc/hostname"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$'/etc/resolv.conf' contains the IP addresses of the DNS nameservers the system uses for name resolution. If this file is missing, empty, or points to an unreachable server, hostname resolution will fail even when IP connectivity is intact. '/etc/hosts' provides local static hostname-to-IP mappings and would only resolve entries listed there. '/etc/nsswitch.conf' controls the order of name resolution sources (files vs DNS) but does not contain nameserver IPs. '/etc/hostname' stores only the local system hostname.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man5/resolv.conf.5.html","label":"man page: resolv.conf"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/configuring_and_managing_networking/index","label":"Red Hat - Configuring the /etc/resolv.conf file"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux server cannot reach any external hosts by hostname, but IP address connectivity works fine. DNS resolution was working yesterday. Which file should the administrator inspect FIRST to verify the system's configured DNS resolver addresses?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is troubleshooting a service that fails to start after a system reboot. The command 'systemctl status myapp.service' shows the unit is in a 'failed' state. Which command should the administrator run NEXT to view the most detailed log output for that specific service?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"cat /var/log/syslog | grep myapp"},{"id":"b","text":"journalctl -u myapp.service -xe"},{"id":"c","text":"dmesg | grep myapp"},{"id":"d","text":"tail -f /var/log/myapp.log"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'journalctl -u myapp.service -xe' queries the systemd journal specifically for the named unit (-u), jumps to the end of the log (-e), and enables extra detail (-x), making it the most targeted and detailed command for diagnosing a failed systemd unit. Grepping /var/log/syslog may not capture all journal entries, especially on systems using only journald without syslog forwarding. 'dmesg' shows kernel ring buffer messages, which are relevant for hardware or driver issues but not application failures. Tailing an application-specific log file requires knowing the log path and may miss systemd-level failure details.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/journalctl.1.html","label":"man page: journalctl"},{"url":"https://www.freedesktop.org/software/systemd/man/latest/journalctl.html","label":"systemd journal documentation"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is troubleshooting a service that fails to start after a system reboot. The command 'systemctl status myapp.service' shows the unit is in a 'failed' state. Which command should the administrator run NEXT to view the most detailed log output for that specific service?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A user reports they cannot write new files to a filesystem even though 'df -h' shows 40% disk space is still available. What is the MOST likely cause of this issue?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The filesystem is mounted as read-only"},{"id":"b","text":"The inode table is exhausted"},{"id":"c","text":"The disk has bad sectors preventing writes"},{"id":"d","text":"The user's home directory quota has been exceeded"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$When 'df -h' shows available block space but writes still fail, the most common cause is inode exhaustion. Each file requires an inode entry; if all inodes are consumed (even with free blocks), no new files can be created. This can be verified with 'df -i'. A read-only mount would prevent all writes and would typically be visible in 'mount' output. Bad sectors would usually produce I/O errors in logs. A quota issue would show a quota-exceeded error message specific to the user, not a general write failure.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/df.1.html","label":"man page: df"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/managing_file_systems/index","label":"Linux Filesystem Inodes - Red Hat Documentation"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A user reports they cannot write new files to a filesystem even though 'df -h' shows 40% disk space is still available. What is the MOST likely cause of this issue?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux administrator notices that a web server process is consuming 98% CPU continuously. Which command would BEST allow the administrator to identify the specific process ID and dynamically monitor its resource usage in real time?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"ps aux --sort=-%cpu | head -20"},{"id":"b","text":"top -o %CPU"},{"id":"c","text":"lsof -p <pid>"},{"id":"d","text":"vmstat 1 10"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The 'top' command with '-o %CPU' sorts processes dynamically by CPU usage in real time, allowing an administrator to continuously monitor which processes are consuming the most CPU and observe changes as they happen. 'ps aux' provides a static snapshot rather than a live view. 'lsof' lists open files for a specific PID and does not monitor CPU. 'vmstat' reports system-wide memory and CPU statistics but does not show per-process detail.$patch$, $patch$Troubleshooting$patch$, 3, $patch$[{"url":"https://www.comptia.org/certifications/linux","label":"CompTIA Linux+ XK0-005 Exam Objectives"},{"url":"https://man7.org/linux/man-pages/man1/top.1.html","label":"man page: top (procps)"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux administrator notices that a web server process is consuming 98% CPU continuously. Which command would BEST allow the administrator to identify the specific process ID and dynamically monitor its resource usage in real time?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer needs to create a Docker image that uses Ubuntu 22.04 as the base image, installs the 'curl' package during the build, and then sets the default command to run '/bin/bash'. Which Dockerfile sequence is correct?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"CMD ubuntu:22.04\nRUN apt-get install -y curl\nFROM /bin/bash"},{"id":"b","text":"FROM ubuntu:22.04\nRUN apt-get update && apt-get install -y curl\nCMD [\"/bin/bash\"]"},{"id":"c","text":"FROM ubuntu:22.04\nCMD [\"/bin/bash\"]\nRUN apt-get update && apt-get install -y curl"},{"id":"d","text":"BASE ubuntu:22.04\nINSTALL curl\nCMD /bin/bash"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$A valid Dockerfile must begin with a FROM instruction to specify the base image. RUN instructions execute commands during the image build and should include 'apt-get update' before 'apt-get install' to ensure the package lists are current. CMD in exec form (JSON array) sets the default container command. Option (a) has the instructions in completely wrong order. Option (c) places CMD before RUN which, while not a build error, is bad practice and means the default command is defined before the package is installed — the CMD would still reference the final state, but the order is unconventional and can cause confusion; more critically, RUN after CMD is valid but the CMD placement here implies misunderstanding. Option (d) uses fictional Dockerfile instructions 'BASE' and 'INSTALL' that do not exist.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://docs.docker.com/reference/dockerfile/","label":"Docker Docs – Dockerfile reference"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer needs to create a Docker image that uses Ubuntu 22.04 as the base image, installs the 'curl' package during the build, and then sets the default command to run '/bin/bash'. Which Dockerfile sequence is correct?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator wants to use Ansible to run a playbook called 'site.yml' against a group of servers defined as 'webservers' in the inventory file '/etc/ansible/hosts'. Which command correctly executes this playbook?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"ansible webservers -m site.yml -i /etc/ansible/hosts"},{"id":"b","text":"ansible-playbook site.yml -l webservers -i /etc/ansible/hosts"},{"id":"c","text":"ansible-playbook -m webservers site.yml"},{"id":"d","text":"ansible site.yml --group webservers"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'ansible-playbook' is the correct command for running playbooks. The '-l' (or '--limit') flag restricts execution to a specific host group, and '-i' specifies the inventory file. Option (a) uses 'ansible' (ad-hoc) with '-m' for modules, not playbooks. Option (c) incorrectly uses '-m' (module flag) with a group name. Option (d) uses an invalid '--group' flag that does not exist in ansible-playbook.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://docs.ansible.com/ansible/latest/cli/ansible-playbook.html","label":"Ansible Docs – ansible-playbook command"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator wants to use Ansible to run a playbook called 'site.yml' against a group of servers defined as 'webservers' in the inventory file '/etc/ansible/hosts'. Which command correctly executes this playbook?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In a Bash script, an administrator uses the following loop:

for i in {1..5}; do
  echo "Iteration $i"
done

What will be the output of this script?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Iteration 0\nIteration 1\nIteration 2\nIteration 3\nIteration 4"},{"id":"b","text":"Iteration 1\nIteration 2\nIteration 3\nIteration 4\nIteration 5"},{"id":"c","text":"Iteration {1..5}"},{"id":"d","text":"Iteration 1\nIteration 2\nIteration 3\nIteration 4"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Bash brace expansion {1..5} generates the sequence 1, 2, 3, 4, 5 (inclusive on both ends). The loop iterates five times, printing 'Iteration 1' through 'Iteration 5'. Option (a) is wrong because sequences start at 1, not 0. Option (c) would only happen if brace expansion were disabled or used inside double quotes. Option (d) is missing the fifth iteration.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://www.gnu.org/software/bash/manual/bash.html#Brace-Expansion","label":"GNU Bash Manual – Brace Expansion"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In a Bash script, an administrator uses the following loop:

for i in {1..5}; do
  echo "Iteration $i"
done

What will be the output of this script?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator reviews a docker-compose.yml file and notices the directive 'restart: always' under a service definition. What is the effect of this setting?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"The container restarts only when it exits with a non-zero exit code."},{"id":"b","text":"The container restarts automatically under any exit condition, including after the Docker daemon restarts."},{"id":"c","text":"The container restarts only if the restart is manually triggered by an administrator."},{"id":"d","text":"The container restarts a maximum of three times before Docker stops attempting restarts."}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'restart: always' instructs Docker to always restart the container regardless of the exit status, and it will also start the container automatically when the Docker daemon starts (e.g., after a system reboot). 'on-failure' only restarts on non-zero exit codes. 'no' (the default) requires manual restarts. 'on-failure' can be configured with a max retry count, not 'always'.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://docs.docker.com/engine/containers/start-containers-automatically/","label":"Docker Docs – Start containers automatically (restart policies)"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator reviews a docker-compose.yml file and notices the directive 'restart: always' under a service definition. What is the effect of this setting?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A sysadmin wants to schedule a script called '/opt/scripts/backup.sh' to run every day at 2:30 AM using cron. Which crontab entry is correct?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"30 2 * * * /opt/scripts/backup.sh"},{"id":"b","text":"2 30 * * * /opt/scripts/backup.sh"},{"id":"c","text":"* * 2 30 * /opt/scripts/backup.sh"},{"id":"d","text":"0 2 30 * * /opt/scripts/backup.sh"}]$patch$::jsonb, $patch$["a"]$patch$::jsonb, $patch$Cron fields are ordered: minute, hour, day-of-month, month, day-of-week. '30 2 * * *' means minute 30, hour 2, every day, every month, every weekday — which corresponds to 2:30 AM daily. Option (b) reverses minute and hour. Option (c) places values in the wrong fields entirely. Option (d) uses '0 2 30' which would only run at 2:00 AM on the 30th day of the month.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man5/crontab.5.html","label":"Linux man page – crontab(5)"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A sysadmin wants to schedule a script called '/opt/scripts/backup.sh' to run every day at 2:30 AM using cron. Which crontab entry is correct?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which instruction in a Dockerfile specifies the command that will be executed by default when a container starts, and can be overridden by providing arguments to 'docker run'?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"RUN"},{"id":"b","text":"ENTRYPOINT"},{"id":"c","text":"CMD"},{"id":"d","text":"EXEC"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$'CMD' sets the default command and/or parameters for a container and is easily overridden by arguments passed to 'docker run'. 'RUN' executes commands during the image build process to create image layers. 'ENTRYPOINT' defines the executable that always runs and is not easily overridden without the --entrypoint flag. 'EXEC' is not a valid Dockerfile instruction.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://docs.docker.com/reference/dockerfile/#cmd","label":"Docker Docs – Dockerfile CMD instruction"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which instruction in a Dockerfile specifies the command that will be executed by default when a container starts, and can be overridden by providing arguments to 'docker run'?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator is writing a Bash script and needs to check whether a file named '/etc/config.conf' exists and is readable before processing it. Which conditional expression correctly performs this check?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"if [ -x /etc/config.conf ]; then"},{"id":"b","text":"if [ -r /etc/config.conf ]; then"},{"id":"c","text":"if [ -w /etc/config.conf ]; then"},{"id":"d","text":"if [ -d /etc/config.conf ]; then"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The '-r' flag tests whether the file exists and is readable by the current user, which is exactly what is required. '-x' tests if the file is executable. '-w' tests if the file is writable. '-d' tests if the path is a directory, not a regular file.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://www.gnu.org/software/bash/manual/bash.html#Bash-Conditional-Expressions","label":"GNU Bash Manual – Bash Conditional Expressions"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator is writing a Bash script and needs to check whether a file named '/etc/config.conf' exists and is readable before processing it. Which conditional expression correctly performs this check?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A developer has a running Docker container named 'webserver' and needs to execute an interactive Bash shell session inside it without stopping the container. Which command achieves this?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"docker run -it webserver /bin/bash"},{"id":"b","text":"docker attach webserver"},{"id":"c","text":"docker exec -it webserver /bin/bash"},{"id":"d","text":"docker start -i webserver"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$'docker exec -it webserver /bin/bash' runs a new Bash process inside an already-running container, providing an interactive TTY session. 'docker run -it' starts a brand new container from an image, not an existing one. 'docker attach' attaches to the container's primary process stdin/stdout which can inadvertently stop it if Ctrl+C is pressed. 'docker start -i' restarts a stopped container, which is not applicable here.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://docs.docker.com/reference/cli/docker/container/exec/","label":"Docker Docs – docker exec"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A developer has a running Docker container named 'webserver' and needs to execute an interactive Bash shell session inside it without stopping the container. Which command achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator wants to pass the output of the 'grep' command as an argument (not via stdin) to a script called 'process.sh'. Which syntax correctly accomplishes this using command substitution?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"process.sh | grep 'pattern' /var/log/syslog"},{"id":"b","text":"process.sh < grep 'pattern' /var/log/syslog"},{"id":"c","text":"process.sh $(grep 'pattern' /var/log/syslog)"},{"id":"d","text":"process.sh && grep 'pattern' /var/log/syslog"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$Command substitution using $() captures the standard output of a command and passes it as an argument to another command. Option (a) pipes stdin to process.sh, not the grep results. Option (b) is invalid syntax for redirection in this context. Option (d) uses a logical AND operator which runs process.sh first and then grep only if process.sh succeeds — it does not pass grep output as an argument.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://www.gnu.org/software/bash/manual/bash.html#Command-Substitution","label":"GNU Bash Manual – Command Substitution"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator wants to pass the output of the 'grep' command as an argument (not via stdin) to a script called 'process.sh'. Which syntax correctly accomplishes this using command substitution?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux administrator needs to write a Bash script that exits immediately if any command within the script fails. Which command should be placed at the top of the script to enforce this behavior?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"set -u"},{"id":"b","text":"set -e"},{"id":"c","text":"set -x"},{"id":"d","text":"set -o pipefail"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'set -e' (errexit) causes the script to exit immediately when any command returns a non-zero exit status. 'set -u' treats unset variables as errors but does not exit on command failure. 'set -x' enables debug tracing, printing each command before execution. 'set -o pipefail' is useful for catching failures in pipelines but alone does not cover all command failures the way 'set -e' does.$patch$, $patch$Scripting, Containers, and Automation$patch$, 3, $patch$[{"url":"https://www.gnu.org/software/bash/manual/bash.html#The-Set-Builtin","label":"GNU Bash Manual – The Set Builtin"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux administrator needs to write a Bash script that exits immediately if any command within the script fails. Which command should be placed at the top of the script to enforce this behavior?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator wants to use firewalld to permanently block all inbound traffic on TCP port 2222 in the 'public' zone while ensuring the rule survives a system reboot. Which command accomplishes this?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"firewall-cmd --zone=public --add-port=2222/tcp --permanent && firewall-cmd --reload"},{"id":"b","text":"firewall-cmd --zone=public --remove-port=2222/tcp --permanent && firewall-cmd --reload"},{"id":"c","text":"firewall-cmd --zone=public --add-rich-rule='rule family=ipv4 port port=2222 protocol=tcp drop' && firewall-cmd --reload"},{"id":"d","text":"firewall-cmd --zone=public --add-block-port=2222/tcp --permanent && firewall-cmd --reload"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$To block inbound TCP traffic on a specific port using firewalld, you first need to ensure the port is not listed as allowed in the zone. The '--remove-port' option with '--permanent' removes the port allowance from the persistent (on-disk) configuration, and '--reload' applies the change to the running ruleset without interrupting existing connections. Option (a) does the opposite — it adds (opens) port 2222, increasing the attack surface. Option (c) is syntactically incorrect as written (missing the '--permanent' flag), and a drop rule via rich-rules is more verbose than necessary for simply removing an allowed port; without '--permanent' it will not survive a reboot. Option (d) uses a non-existent '--add-block-port' flag, which is not a valid firewall-cmd option and will produce an error.$patch$, $patch$Security$patch$, 3, $patch$[{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/securing_networks/using-and-configuring-firewalld_securing-networks","label":"Red Hat – Using and Configuring firewalld"},{"url":"https://firewalld.org/documentation/man-pages/firewall-cmd.html","label":"firewalld.org – firewall-cmd man page"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator wants to use firewalld to permanently block all inbound traffic on TCP port 2222 in the 'public' zone while ensuring the rule survives a system reboot. Which command accomplishes this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A security auditor reviewing a Linux server notices that the sticky bit is not set on the /tmp directory. What is the primary security risk of this misconfiguration, and which command correctly remediates it?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"Any user can read files in /tmp owned by other users; remediated by running: chmod 1777 /tmp"},{"id":"b","text":"Any user can delete or rename files in /tmp owned by other users; remediated by running: chmod 1777 /tmp"},{"id":"c","text":"The root user loses write access to /tmp; remediated by running: chmod 0777 /tmp"},{"id":"d","text":"Executable files in /tmp can be run by unprivileged users; remediated by running: chmod 0755 /tmp"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The sticky bit (mode bit 1000) on a world-writable directory like /tmp restricts file deletion and renaming so that only the file owner, the directory owner, or root can remove or rename files within it. Without the sticky bit, any user with write permission to /tmp could delete or rename files belonging to other users, enabling denial-of-service or privilege-escalation attacks. The correct remediation is 'chmod 1777 /tmp', which preserves world read/write/execute permissions (0777) and adds the sticky bit (1000). Option (a) incorrectly identifies the risk as a read issue — the sticky bit does not affect read permissions. Option (c) removes the sticky bit entirely. Option (d) removes write access for group and others, breaking /tmp's intended purpose.$patch$, $patch$Security$patch$, 3, $patch$[{"url":"https://www.man7.org/linux/man-pages/man1/chmod.1.html","label":"Linux man page – chmod(1)"},{"url":"https://www.comptia.org/certifications/linux","label":"CompTIA Linux+ Study Guide – File Permissions and Special Bits"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A security auditor reviewing a Linux server notices that the sticky bit is not set on the /tmp directory. What is the primary security risk of this misconfiguration, and which command correctly remediates it?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux administrator needs to configure the system so that all unsuccessful login attempts for the root account are logged and the account is temporarily locked after 4 consecutive failed attempts within a single session. Which PAM module and configuration file should the administrator modify to enforce this policy?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"pam_tally2 module configured in /etc/pam.d/common-auth"},{"id":"b","text":"pam_faillock module configured in /etc/pam.d/system-auth"},{"id":"c","text":"pam_unix module configured in /etc/pam.d/login"},{"id":"d","text":"pam_cracklib module configured in /etc/security/pwquality.conf"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$pam_faillock is the modern, recommended PAM module for tracking consecutive authentication failures and temporarily locking accounts after a configurable threshold is exceeded. It replaces the deprecated pam_tally2 and is configured within /etc/pam.d/system-auth (or /etc/pam.d/password-auth on RHEL-based systems). pam_unix handles standard Unix password authentication but does not provide account-lockout functionality on its own. pam_cracklib (now superseded by pam_pwquality) enforces password complexity rules, not lockout policies. pam_tally2 is deprecated in modern Linux distributions and should no longer be used.$patch$, $patch$Security$patch$, 3, $patch$[{"url":"https://www.man7.org/linux/man-pages/man8/pam_faillock.8.html","label":"Linux-PAM: pam_faillock documentation"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/security_hardening/configuring-account-locking_security-hardening","label":"Red Hat – Configuring account locking with pam_faillock"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P1$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux administrator needs to configure the system so that all unsuccessful login attempts for the root account are logged and the account is temporarily locked after 4 consecutive failed attempts within a single session. Which PAM module and configuration file should the administrator modify to enforce this policy?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux administrator needs to change the default runlevel so that the system boots into multi-user mode with networking but WITHOUT a graphical desktop environment. Which systemd target should be set as the default?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"graphical.target"},{"id":"b","text":"multi-user.target"},{"id":"c","text":"rescue.target"},{"id":"d","text":"network-online.target"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$multi-user.target is the systemd equivalent of SysV runlevel 3 — it provides a fully operational multi-user environment with networking but without a graphical display manager. graphical.target (runlevel 5) adds a GUI on top of multi-user.target. rescue.target (runlevel 1) is a single-user maintenance mode with minimal services. network-online.target is a synchronization point that ensures the network is up, not a boot target by itself.$patch$, $patch$System Management$patch$, 3, $patch$[{"url":"https://www.freedesktop.org/software/systemd/man/systemd.special.html","label":"systemd.special(7) — systemd target units"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/working-with-systemd-targets_configuring-basic-system-settings","label":"Red Hat — Working with systemd targets"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P2$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Linux administrator needs to change the default runlevel so that the system boots into multi-user mode with networking but WITHOUT a graphical desktop environment. Which systemd target should be set as the default?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator wants to persistently mount an NFS share located at 192.168.10.50:/exports/data to /mnt/data on a Linux client so that the mount survives reboots. The mount should use NFSv4 and mount lazily at boot. Which /etc/fstab entry is correct?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"192.168.10.50:/exports/data  /mnt/data  nfs  defaults  0  0"},{"id":"b","text":"192.168.10.50:/exports/data  /mnt/data  nfs4  noauto,x-systemd.automount  0  0"},{"id":"c","text":"192.168.10.50:/exports/data  /mnt/data  nfs4  defaults  0  0"},{"id":"d","text":"192.168.10.50:/exports/data  /mnt/data  nfs  vers=4,noauto  0  0"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$Using filesystem type 'nfs4' along with 'noauto,x-systemd.automount' configures systemd to create an automount unit that mounts the NFS share lazily on first access rather than strictly at boot time, which prevents boot failures if the NFS server is temporarily unreachable. Option A uses the generic 'nfs' type with 'defaults', which forces a mount attempt at boot and can hang the system. Option C specifies nfs4 with defaults but still blocks at boot. Option D mixes generic 'nfs' with 'vers=4' and 'noauto', which prevents automatic mounting entirely without the automount helper.$patch$, $patch$System Management$patch$, 3, $patch$[{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/managing_file_systems/mounting-nfs-shares_managing-file-systems","label":"Red Hat — Mounting NFS shares persistently"},{"url":"https://documentation.ubuntu.com/server/how-to/networking/install-nfs/","label":"Ubuntu Server Guide — Network File System (NFS)"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P2$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator wants to persistently mount an NFS share located at 192.168.10.50:/exports/data to /mnt/data on a Linux client so that the mount survives reboots. The mount should use NFSv4 and mount lazily at boot. Which /etc/fstab entry is correct?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A system administrator notices a package on a RHEL-compatible system is broken and wants to reinstall it without removing it first. The package name is 'curl'. Which command accomplishes this using the DNF package manager?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"dnf install --force curl"},{"id":"b","text":"dnf reinstall curl"},{"id":"c","text":"dnf update curl"},{"id":"d","text":"dnf remove curl && dnf install curl"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$'dnf reinstall curl' downloads and reinstalls the currently installed version of the package, restoring any modified or missing files without requiring removal first. 'dnf install --force' is not a valid DNF syntax and would produce an error. 'dnf update curl' only upgrades the package if a newer version is available; it will not reinstall the same version. 'dnf remove && dnf install' is a two-step workaround that could disrupt dependent services and risks dependency issues during the removal phase.$patch$, $patch$System Management$patch$, 3, $patch$[{"url":"https://dnf.readthedocs.io/en/latest/command_ref.html#reinstall-command-label","label":"DNF Command Reference — reinstall"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/managing_software_with_the_dnf_tool/index","label":"Red Hat — Managing software with DNF"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P2$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A system administrator notices a package on a RHEL-compatible system is broken and wants to reinstall it without removing it first. The package name is 'curl'. Which command accomplishes this using the DNF package manager?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An administrator needs to schedule a one-time task to run the script /opt/scripts/backup.sh tomorrow at 02:30 AM on a Linux system. Which command achieves this?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"crontab -e and add: 30 2 * * * /opt/scripts/backup.sh"},{"id":"b","text":"at 02:30 tomorrow < /opt/scripts/backup.sh"},{"id":"c","text":"echo '/opt/scripts/backup.sh' | at 02:30"},{"id":"d","text":"systemd-run --on-calendar='tomorrow 02:30' /opt/scripts/backup.sh"}]$patch$::jsonb, $patch$["b"]$patch$::jsonb, $patch$The 'at' command is designed for one-time scheduled task execution. 'at 02:30 tomorrow < /opt/scripts/backup.sh' reads the script as input and schedules it for 02:30 the next day. crontab is for recurring tasks — the entry in option A would run the script every day at 02:30, not just once. Option C uses echo to pipe only the path string into 'at', which would attempt to run the text as a command without the script's contents; this also lacks 'tomorrow'. Option D uses systemd-run which can work for transient timers but the calendar syntax 'tomorrow 02:30' is not the correct systemd OnCalendar format.$patch$, $patch$System Management$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man1/at.1p.html","label":"Linux man page — at(1)"},{"url":"https://access.redhat.com/documentation/en-us/red_hat_enterprise_linux/9/html/configuring_basic_system_settings/assembly_scheduling-tasks_configuring-basic-system-settings","label":"Red Hat — Scheduling tasks with at"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = $patch$XK0-005-P2$patch$
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An administrator needs to schedule a one-time task to run the script /opt/scripts/backup.sh tomorrow at 02:30 AM on a Linux system. Which command achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Linux administrator wants to display all currently active swap areas including their type, size, and usage on a running system. Which command provides this information?$patch$, 'SINGLE'::"QType", $patch$[{"id":"a","text":"fdisk -l"},{"id":"b","text":"free -h"},{"id":"c","text":"swapon --show"},{"id":"d","text":"lsblk --fs"}]$patch$::jsonb, $patch$["c"]$patch$::jsonb, $patch$'swapon --show' lists all active swap areas with columns for name, type (partition or file), size, used space, and priority. 'fdisk -l' lists disk partition tables but does not distinguish or report on active swap usage. 'free -h' shows a memory summary that includes a total swap line, but it does not detail individual swap areas or their types. 'lsblk --fs' shows block devices with filesystem information but does not report swap utilization or confirm whether a swap area is currently active.$patch$, $patch$System Management$patch$, 3, $patch$[{"url":"https://man7.org/linux/man-pages/man8/swapon.8.html","label":"Linux man page — swapon(8)"},{"url":"https://wiki.archlinux.org/title/Swap","label":"Arch Linux Wiki — Swap"}]$patch$::jsonb, 'DRAFT'::"QStatus", 'manual:xk0-005-topup', false, NOW(), NOW()
